import * as React from 'react';
//import * as PropTypes from 'prop-types';
import { graphql } from 'gatsby';
import useIntlHelper from '~src/_i18n/helpers/useIntlHelper';
import Link from '~src/_i18n/components/Link';
import Layout from '~src/components/Layout/Layout';
import { PostFeed } from '~src/components/Sections/Posts/PostFeed/PostFeed';
import { NotFound as NotFoundData } from '~src/pages/__generated__/NotFound';
import * as styles from './404.module.scss';

const NotFoundPage: React.FC<{ data: NotFoundData }> = ({ data }) => {
	const { formatMessage } = useIntlHelper();
	return (
		<Layout template="notfound">
			<div className="inner error-content">
				<section className={styles.errorMessage}>
					<h1 className={styles.errorCode}>404</h1>
					<p className={styles.errorDescription}>{formatMessage('notFound.title')}</p>
					<Link to="/" className={styles.errorLink}>
						{formatMessage('notFound.goBack')}
					</Link>
				</section>
				<PostFeed data={data} />
			</div>
		</Layout>
	);
};

export default NotFoundPage;

export const notFoundQuery = graphql`
	query NotFound($locale: String!) {
		posts: allMdx(
			sort: { fields: [frontmatter___date], order: DESC }
			limit: 3
			filter: { fields: { category: { eq: "posts" }, locale: { eq: $locale } } }
		) {
			nodes {
				frontmatter {
					date(formatString: "DD MMMM YYYY")
					title
					tags
					image {
						childImageSharp {
							gatsbyImageData(layout: FIXED)
						}
					}
				}
				fields {
					locale
					slug
					category
				}
				excerpt(pruneLength: 200)
				timeToRead
			}
		}
	}
`;
